cd /opt/mediguard-pro || exit 1
stamp=$(date +%Y%m%d%H%M%S)
mkdir -p /tmp/mediguard-backend-backup-$stamp/modules
cp -a backend/main.py /tmp/mediguard-backend-backup-$stamp/main.py
cp -a backend/modules/batch_scan_runner.py backend/modules/resume_quality.py /tmp/mediguard-backend-backup-$stamp/modules/
[ -f backend/modules/jkn_non_covered_filter.py ] && cp -a backend/modules/jkn_non_covered_filter.py /tmp/mediguard-backend-backup-$stamp/modules/ || true
echo "backup=/tmp/mediguard-backend-backup-$stamp"
cat >/tmp/mediguard-e0e411a.patch.gz.b64 <<'B64'

B64
base64 -d /tmp/mediguard-e0e411a.patch.gz.b64 | gzip -d > /tmp/mediguard-e0e411a.patch
if ! patch -p1 --forward < /tmp/mediguard-e0e411a.patch; then
  echo 'Patch may already be applied. Checking markers...'
  grep -R "jkn_non_covered_filter" -n backend/main.py backend/modules/batch_scan_runner.py
  test -f backend/modules/jkn_non_covered_filter.py
  grep -R "hd_cdl_malfunction_anamnesis_incomplete" -n backend/modules/resume_quality.py
fi
python3 -m py_compile backend/main.py backend/modules/batch_scan_runner.py backend/modules/resume_quality.py backend/modules/jkn_non_covered_filter.py
docker compose up -d --build api
docker compose ps api
docker compose exec -T api python - <<'PY'
from modules.jkn_non_covered_filter import build_jkn_non_covered_alerts
from modules.resume_quality import build_resume_quality_issues
print('jkn_filter_ok', build_jkn_non_covered_alerts({'diagnosa_utama':'kecelakaan lalu lintas Jasa Raharja'})[0]['pattern'])
print('hd_cdl_rule_ok', build_resume_quality_issues({'diagnosa_utama':'CKD on HD','keluhan_utama':'CDL malfunction','lain_lain':'kontrol HD rutin'})[-1]['pattern'])
PY
curl -sS http://127.0.0.1:8080/api/v1/health
